manifest.install:
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_case` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(300) NOT NULL DEFAULT '', `image` varchar(300) NOT NULL DEFAULT '', `erweima` varchar(300) NOT NULL DEFAULT '', `domainid` int(11) NOT NULL, `addtime` int(10) NOT NULL, `category` int(11) NOT NULL COMMENT '类别', `ord` int(11) DEFAULT '0', `myurl` varchar(300) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_case_category` ( `id` int(11) NOT NULL AUTO_INCREMENT, `categoryname` varchar(90) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '分类名', `domainid` int(11) NOT NULL, `ord` int(10) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_cert` ( `id` bigint(11) NOT NULL AUTO_INCREMENT, `domainid` bigint(11) NOT NULL, `name` varchar(60) DEFAULT NULL, `image` varchar(500) DEFAULT NULL, `addtime` int(10) NOT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_customer` ( `id` bigint(11) NOT NULL AUTO_INCREMENT, `domainid` bigint(11) NOT NULL, `title` varchar(60) DEFAULT NULL, `image` varchar(500) DEFAULT NULL, `addtime` int(10) NOT NULL, `dizhi` varchar(300) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_domain` ( `id` int(10) NOT NULL AUTO_INCREMENT, `domain` varchar(100) NOT NULL, `username` varchar(30) DEFAULT NULL, `isfounder` smallint(1) NOT NULL DEFAULT '0', `val` longtext, `addtime` int(10) NOT NULL, `loginset` text, `banner` longtext, `ourservice` longtext, `development` longtext, `cando` longtext, `youshi` longtext, `title` longtext, `menu` longtext, `daili` longtext, `module` varchar(30) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=47 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_help` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(300) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '新闻标题', `content` mediumtext CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '新闻内容', `domainid` int(11) NOT NULL, `addtime` int(10) NOT NULL, `category` int(11) NOT NULL COMMENT '类别', `abstract` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '摘要', `keywords` varchar(900) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL, `description` varchar(900) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL, `num` int(11) NULL DEFAULT NULL, `image` varchar(300) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL, PRIMARY KEY (`id`) USING BTREE ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_help_category` ( `id` int(11) NOT NULL AUTO_INCREMENT, `categoryname` varchar(90) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '分类名', `domainid` int(11) NOT NULL, `ord` int(10) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_news` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(300) NOT NULL DEFAULT '' COMMENT '新闻标题', `content` mediumtext COMMENT '新闻内容', `domainid` int(11) NOT NULL, `addtime` int(10) NOT NULL, `category` int(11) NOT NULL COMMENT '类别', `abstract` text COMMENT '摘要', `keywords` varchar(900) DEFAULT NULL, `description` varchar(900) DEFAULT NULL, `num` int(11) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_news_category` ( `id` int(11) NOT NULL AUTO_INCREMENT, `categoryname` varchar(90) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '分类名', `domainid` int(11) NOT NULL, `ord` int(10) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_rukou` ( `id` bigint(11) NOT NULL AUTO_INCREMENT, `domainid` bigint(11) NOT NULL, `title` varchar(60) DEFAULT NULL, `abstract` varchar(120) DEFAULT NULL, `image` varchar(500) DEFAULT NULL, `addtime` int(10) NOT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_solve` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(300) NOT NULL DEFAULT '', `content` mediumtext COMMENT '新闻内容', `domainid` int(11) NOT NULL, `addtime` int(10) NOT NULL, `category` int(11) NOT NULL COMMENT '类别', `count` int(11) NOT NULL, `keywords` varchar(900) DEFAULT NULL, `description` varchar(900) DEFAULT NULL, `image` varchar(600) DEFAULT NULL, `erweima` varchar(600) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_mogucms_guanwang_team` ( `id` bigint(11) NOT NULL AUTO_INCREMENT, `domainid` bigint(11) NOT NULL, `name` varchar(60) DEFAULT NULL, `zhiwei` varchar(60) DEFAULT NULL, `image` varchar(500) DEFAULT NULL, `addtime` int(10) NOT NULL, PRIMARY KEY (`id`) ) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8;

manifest.uninstall:
DROP TABLE IF EXISTS `ims_mogucms_guanwang_case`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_case_category`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_cert`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_customer`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_domain`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_help`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_help_category`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_news`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_news_category`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_rukou`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_solve`;
DROP TABLE IF EXISTS `ims_mogucms_guanwang_team`;
